import type { VercelRequest, VercelResponse } from '@vercel/node';
import { GoogleGenAI } from '@google/genai';
import { getAnalysisPrompt } from './_prompts.js';
import { AnalysisResult, GroundingSource } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

const getValidatedTextFromResponse = (response: any): string => {
    const responseText = response.text;
    if (responseText && typeof responseText === 'string') return responseText;
    const finishReason = response.candidates?.[0]?.finishReason;
    if (finishReason && finishReason !== 'STOP') {
        if (finishReason === 'SAFETY') throw new Error(`Safety block.`);
        throw new Error(`AI terminated. Reason: ${finishReason}.`);
    }
    throw new Error("Empty response.");
};

const robustJsonParse = (jsonString: string) => {
    let cleanJsonString = jsonString.trim();
    const markdownMatch = cleanJsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    if (markdownMatch && markdownMatch[2]) {
        cleanJsonString = markdownMatch[2];
    } else {
        const firstBracket = cleanJsonString.indexOf('{');
        const lastBracket = cleanJsonString.lastIndexOf('}');
        if (firstBracket !== -1 && lastBracket > firstBracket) cleanJsonString = cleanJsonString.substring(firstBracket, lastBracket + 1);
    }
    try {
        return JSON.parse(cleanJsonString);
    } catch (e) {
        throw new Error("Malformed JSON.");
    }
};

export default async function handler(req: VercelRequest, res: VercelResponse) {
    if (req.method !== 'POST') return res.status(405).json({ message: 'Method Not Allowed' });

    try {
        const { imageParts, riskReward, tradingStyle, isSeasonal, userSettings } = req.body;
        const prompt = getAnalysisPrompt(tradingStyle, riskReward, isSeasonal, userSettings);
        const parts: any[] = [{ text: prompt }];
        for (const key of ['higher', 'primary', 'entry']) {
            if (imageParts[key]) {
                parts.push({ text: `${key.charAt(0).toUpperCase() + key.slice(1)} Timeframe Chart:` });
                parts.push(imageParts[key]);
            }
        }
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-lite',
            contents: { parts },
            config: { temperature: 0, tools: [{ googleSearch: {} }] }
        });
        const responseText = getValidatedTextFromResponse(response);
        const parsedResult = robustJsonParse(responseText);
        return res.status(200).json(parsedResult);
    } catch (error: any) {
        console.error("Error in /api/analyze:", error);
        return res.status(500).json({ message: error.message || 'Error' });
    }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { GoogleGenAI } from '@google/genai';
import { getChatSystemInstruction } from './_prompts.js';
import { ChatMessage, GroundingSource } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

export default async function handler(req: VercelRequest, res: VercelResponse) {
    if (req.method !== 'POST') {
        res.setHeader('Allow', 'POST');
        return res.status(405).json({ message: 'Method Not Allowed' });
    }

    try {
        const { history, newMessageParts } = req.body;
        if (!Array.isArray(history) || !Array.isArray(newMessageParts)) {
            return res.status(400).json({ message: 'Invalid request body' });
        }

        const contents = history.map((msg: ChatMessage) => ({ 
            role: msg.role, 
            parts: msg.parts.map(p => p.text ? { text: p.text } : p)
        }));
        contents.push({ role: 'user', parts: newMessageParts });

        const responseStream = await ai.models.generateContentStream({
            model: 'gemini-2.5-flash-lite',
            contents: contents,
            config: { systemInstruction: getChatSystemInstruction(), tools: [{ googleSearch: {} }] },
        });

        res.setHeader('Content-Type', 'application/json');
        res.setHeader('Transfer-Encoding', 'chunked');

        let allSources: GroundingSource[] = [];

        for await (const chunk of responseStream) {
            const responseChunk: { textChunk?: string; sources?: GroundingSource[] } = {};
            if (chunk.text) {
                responseChunk.textChunk = chunk.text;
            }
            if (chunk.candidates?.[0]?.groundingMetadata?.groundingChunks) {
                const chunkSources: GroundingSource[] = chunk.candidates[0].groundingMetadata.groundingChunks
                    .map((c: any) => ({ uri: c.web?.uri || '', title: c.web?.title || 'Source' }))
                    .filter((s: GroundingSource) => s.uri);

                const newSources = chunkSources.filter((cs) => !allSources.some(as => as.uri === cs.uri));

                if (newSources.length > 0) {
                    allSources = [...allSources, ...newSources];
                    responseChunk.sources = allSources;
                }
            }
            if (Object.keys(responseChunk).length > 0) {
                res.write(JSON.stringify(responseChunk) + '\n');
            }
        }
        res.end();

    } catch (error: any) {
        console.error("Error in /api/chat:", error);
        // If headers are not sent, send an error response. Otherwise, just end.
        if (!res.headersSent) {
            res.status(500).json({ message: error.message || 'An internal server error occurred.' });
        } else {
            res.end();
        }
    }
}

import type { VercelRequest, VercelResponse } from '@vercel/node';
import { GoogleGenAI, Type } from '@google/genai';
import * as Prompts from './_prompts.js';
import { 
    DashboardOverview, 
    MarketSentimentResult, 
    JournalFeedback, 
    PredictedEvent, 
    TradeEntry, 
    GroundingSource 
} from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });

const getValidatedTextFromResponse = (response: any): string => {
    const responseText = response.text;

    if (responseText && typeof responseText === 'string') {
        return responseText;
    }

    const finishReason = response.candidates?.[0]?.finishReason;
    if (finishReason && finishReason !== 'STOP') {
        if (finishReason === 'SAFETY') {
            throw new Error(`Request blocked for safety reasons.`);
        }
        throw new Error(`The AI's response was terminated. Reason: ${finishReason}.`);
    }

    throw new Error("The AI returned an empty or invalid response.");
};

const extractSources = (response: any): GroundingSource[] => {
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        return response.candidates[0].groundingMetadata.groundingChunks
            .map((c: any) => ({ uri: c.web?.uri || '', title: c.web?.title || 'Source' }))
            .filter((s: GroundingSource) => s.uri);
    }
    return [];
};

const isDashboardOverview = (data: any): data is DashboardOverview => {
    return (
        data &&
        data.marketCondition &&
        ['Bullish', 'Bearish', 'Neutral'].includes(data.marketCondition.sentiment) &&
        Array.isArray(data.marketCondition.trendingPairs) &&
        Array.isArray(data.dailyBiases) &&
        data.dailyBiases.length > 0 &&
        data.tradingOpportunities &&
        Array.isArray(data.tradingOpportunities.highProbabilitySetups) &&
        data.tradingOpportunities.highProbabilitySetups.length >= 1
    );
};

const isMarketSentimentResult = (data: any): data is MarketSentimentResult => {
    return (
        data &&
        typeof data.asset === 'string' &&
        ['Bullish', 'Bearish', 'Neutral'].includes(data.sentiment) &&
        typeof data.summary === 'string'
    );
};

const isJournalFeedback = (data: any): data is JournalFeedback => {
    return (
        data &&
        typeof data.overallPnl === 'number' &&
        typeof data.winRate === 'number'
    );
};

const isPredictedEvent = (data: any): data is PredictedEvent => {
    return (
        data &&
        typeof data.event_description === 'string' &&
        typeof data.day === 'string' &&
        ['BUY', 'SELL'].includes(data.direction)
    );
};

const isPredictedEventArray = (data: any): data is PredictedEvent[] => {
    return Array.isArray(data);
};

const robustJsonParse = (jsonString: string) => {
    if (typeof jsonString !== 'string' || !jsonString) {
        throw new Error("The AI's response was unclear or in an unexpected format.");
    }
    let cleanJsonString = jsonString.trim();
    const markdownMatch = cleanJsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    if (markdownMatch && markdownMatch[2]) {
        cleanJsonString = markdownMatch[2];
    } else {
        const firstBracket = cleanJsonString.indexOf('{');
        const firstSquare = cleanJsonString.indexOf('[');
        let start = -1;
        if (firstBracket === -1) start = firstSquare;
        else if (firstSquare === -1) start = firstBracket;
        else start = Math.min(firstBracket, firstSquare);

        if (start !== -1) {
            const lastBracket = cleanJsonString.lastIndexOf('}');
            const lastSquare = cleanJsonString.lastIndexOf(']');
            const end = Math.max(lastBracket, lastSquare);
            if (end > start) {
                cleanJsonString = cleanJsonString.substring(start, end + 1);
            }
        }
    }
    try {
        return JSON.parse(cleanJsonString);
    } catch (e) {
        throw new Error("The AI's response was unclear or in an unexpected format.");
    }
};

