    const apiCall = async () => {
        if (environment === 'aistudio') {
            const prompt = Prompts.getAnalysisPrompt(tradingStyle, riskReward, isSeasonal, userSettings);
            const parts: any[] = [{ text: prompt }];
            for (const key of ['higher', 'primary', 'entry']) {
