export default async function handler(req: VercelRequest, res: VercelResponse) {
    if (req.method !== 'POST') {
        return res.status(405).json({ message: 'Method Not Allowed' });
    }

    try {
        const { action, payload } = req.body;

        if (!action) {
            if (req.body.command) {
                 const response = await ai.models.generateContent({
                    model: 'gemini-2.5-flash-lite-preview',
                    contents: req.body.command,
                    config: { tools: agentTools }
                });
                const functionCalls = response.functionCalls || null;
                const text = functionCalls ? '' : (response.text || '');
                return res.status(200).json({ text, functionCalls });
            }
            return res.status(400).json({ message: 'Missing action.' });
        }

        switch (action) {
            case 'agent': {
                const response = await ai.models.generateContent({
                    model: 'gemini-2.5-flash-lite-preview',
                    contents: payload.command,
                    config: { tools: agentTools }
                });
                const functionCalls = response.functionCalls || null;
                const text = functionCalls ? '' : (response.text || '');
                return res.status(200).json({ text, functionCalls });
            }

            case 'dashboardOverview': {
                const { isSeasonal } = payload;
                const prompt = Prompts.getDashboardOverviewPrompt(isSeasonal);
                const response = await ai.models.generateContent({ 
                    model: 'gemini-2.5-flash-lite-preview', 
                    contents: prompt,
                    config: { tools: [{ googleSearch: {} }] } 
                });
                const responseText = getValidatedTextFromResponse(response);
                const parsedResult = robustJsonParse(responseText);
                if (!isDashboardOverview(parsedResult)) {
                    throw new Error("The AI's market overview was incomplete or malformed.");
                }
                parsedResult.lastUpdated = Date.now();
                parsedResult.sources = extractSources(response);
                return res.status(200).json(parsedResult);
            }

            case 'marketNews': {
                const prompt = Prompts.getMarketSentimentPrompt(payload.asset);
                const response = await ai.models.generateContent({ 
                    model: 'gemini-2.5-flash-lite-preview', 
                    contents: prompt,
                    config: { tools: [{ googleSearch: {} }] } 
                });
                const responseText = getValidatedTextFromResponse(response);
                const parsedResult = robustJsonParse(responseText);
                if (!isMarketSentimentResult(parsedResult)) {
                    throw new Error("The AI's market sentiment analysis was incomplete or malformed.");
                }
                parsedResult.sources = extractSources(response);
                return res.status(200).json(parsedResult);
            }

            case 'predictions': {
                const prompt = Prompts.getPredictorPrompt();
                const response = await ai.models.generateContent({
                    model: 'gemini-2.5-flash-lite-preview',
                    contents: prompt,
                    config: { tools: [{ googleSearch: {} }] } 
                });
                const responseText = getValidatedTextFromResponse(response);
                const parsedResult = robustJsonParse(responseText) as PredictedEvent[];
                if (!isPredictedEventArray(parsedResult)) {
                    throw new Error("The AI's predictions were incomplete or malformed.");
                }
                const sources = extractSources(response);
                const updatedResult = parsedResult.map(event => ({ ...event, sources }));
                return res.status(200).json(updatedResult);
            }

            case 'journalFeedback': {
                const prompt = Prompts.getJournalFeedbackPrompt(payload.trades);
                const response = await ai.models.generateContent({
                    model: 'gemini-2.5-flash-lite-preview',
                    contents: prompt,
                    config: { responseMimeType: 'application/json' }
                });
                const responseText = getValidatedTextFromResponse(response);
                const parsedResult = robustJsonParse(responseText);
                if (!isJournalFeedback(parsedResult)) {
                    throw new Error("The AI's journal feedback was incomplete or malformed.");
                }
                return res.status(200).json(parsedResult);
            }

            case 'createBot': {
                const prompt = Prompts.getBotPrompt(payload.description, payload.language);
                const response = await ai.models.generateContent({ model: 'gemini-2.5-flash-lite-preview', contents: prompt });
                const code = getValidatedTextFromResponse(response);
                return res.status(200).json({ code });
            }

            case 'createIndicator': {
                const prompt = Prompts.getIndicatorPrompt(payload.description, payload.language);
                const response = await ai.models.generateContent({ model: 'gemini-2.5-flash-lite-preview', contents: prompt });
                const code = getValidatedTextFromResponse(response);
                return res.status(200).json({ code });
            }

            default:
                return res.status(400).json({ message: 'Invalid action.' });
        }

    } catch (error: any) {
        console.error(`Error in /api/agent [action=${req.body.action}]:`, error);
        return res.status(500).json({ message: error.message || 'An internal server error occurred.' });
    }
}

import * as Prompts from './prompts';
import {
  AnalysisResult,
  BotLanguage,
  IndicatorLanguage,
  GroundingSource,
  MarketSentimentResult,
  TradeEntry,
  JournalFeedback,
  ChatMessage,
  ChatMessagePart,
  PredictedEvent,
  DashboardOverview,
  UserSettings,
} from '../types';
import { GoogleGenAI, Type } from '@google/genai';
import { detectEnvironment } from '../hooks/useEnvironment';

const environment = detectEnvironment();

// --- Helper to get a fresh GenAI client on every call ---
const getGenAIClient = () => {
    if (environment !== 'aistudio') {
        throw new Error("Direct GenAI client calls are only available in the AI Studio environment.");
    }
    // CRITICAL: Create a new instance for each call to ensure the latest API key is used.
    return new GoogleGenAI({ apiKey: process.env.API_KEY! });
};

// --- Helper Functions for Backend Communication ---

const withRetry = async <T>(apiCall: () => Promise<T>, maxRetries = 3, initialDelay = 2000): Promise<T> => {
    let attempt = 0;
    while (attempt < maxRetries) {
        try {
            return await apiCall();
        } catch (error: any) {
            attempt++;
            const errorMessage = (error.message || '').toLowerCase();

            if (errorMessage.includes('permission denied') || errorMessage.includes('requested entity was not found')) {
                 if (environment === 'aistudio') {
                    console.warn("Permission denied error detected. Dispatching event to reset API key selection.");
                    window.dispatchEvent(new CustomEvent('resetApiKeySelection'));
                 }
                 throw new Error("API Key Permission Denied. Please re-select a valid API key from a project with billing enabled and try again.");
            }

            const isQuotaExceeded = errorMessage.includes('429') || 
                                   errorMessage.includes('quota') || 
                                   errorMessage.includes('rate limit');

            const isOverloaded = errorMessage.includes('503') || 
                                 errorMessage.includes('504') ||
                                 errorMessage.includes('overloaded') || 
                                 errorMessage.includes('unavailable');

            if ((isQuotaExceeded || isOverloaded) && attempt < maxRetries) {
                const multiplier = isQuotaExceeded ? 5 : 2;
                const delay = initialDelay * Math.pow(multiplier, attempt - 1);
                console.warn(`API Quota/Load issue. Retrying in ${delay}ms... (Attempt ${attempt}/${maxRetries})`);
                await new Promise(resolve => setTimeout(resolve, delay));
            } else if (isQuotaExceeded) {
                throw new Error("Gemini API quota exceeded. Please wait 60 seconds before trying again to allow the rate limit to reset.");
            } else if (isOverloaded) {
                throw new Error("The AI service is currently overloaded. Please try again in a few moments.");
            } else {
                throw error;
            }
        }
    }
    throw new Error('API call failed after multiple retries.');
};

async function postToApi<T>(endpoint: string, body: any): Promise<T> {
    const res = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
    });
    if (!res.ok) {
        const error = await res.json().catch(() => ({ message: res.statusText }));
        const errorMessage = `API Error (${res.status}): ${error.message || 'An unknown error occurred.'}`;
        throw new Error(errorMessage);
    }
    return res.json() as Promise<T>;
}

