    options: { 
        maxRetries?: number; 
        onRetryAttempt?: (attempt: number, maxRetries: number) => void;
    } = {}
): Promise<T> => {
    const { maxRetries = 5, onRetryAttempt } = options;
    const initialDelay = 2000;

    let attempt = 0;
    while (attempt < maxRetries) {
