import React, { useEffect, useRef } from 'react';
import { useTheme } from '../hooks/useTheme';

const NeuralNetworkBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const { theme } = useTheme();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let particles: Particle[] = [];
    let animationFrameId: number;
    let mouseX = -1000;
    let mouseY = -1000;

    const particleCount = Math.min(window.innerWidth / 10, 150); // Responsive count
    const connectionDistance = 150;
    const mouseRepelDistance = 200;

    // Colors based on theme - UPDATED to Deep Navy/Emerald
    const getNodeColor = () => theme === 'dark' ? 'rgba(255, 255, 255, 0.5)' : 'rgba(255, 255, 255, 0.3)';
    const getLineColor = (opacity: number) => theme === 'dark' 
      ? `rgba(52, 211, 153, ${opacity})` // Emerald 400
      : `rgba(16, 185, 129, ${opacity})`; // Emerald 500

    class Particle {
      x: number;
      y: number;
      vx: number;
      vy: number;
      size: number;

      constructor() {
        this.x = Math.random() * canvas!.width;
        this.y = Math.random() * canvas!.height;
        this.vx = (Math.random() - 0.5) * 0.5;
        this.vy = (Math.random() - 0.5) * 0.5;
        this.size = Math.random() * 2 + 1;
      }

      update() {
        // Natural movement
        this.x += this.vx;
        this.y += this.vy;

        // Interactive drift: particles drift in the direction of the cursor relative to center
        // This adds a "wind" effect based on mouse position
        if (mouseX > 0 && mouseY > 0) {
            const centerX = canvas!.width / 2;
            const centerY = canvas!.height / 2;
            // Normalized offset from center (-1 to 1 range roughly)
            const driftX = (mouseX - centerX) * 0.0001; 
            const driftY = (mouseY - centerY) * 0.0001;

            this.x += driftX;
            this.y += driftY;
        }

        // Bounce off edges
        if (this.x < 0 || this.x > canvas!.width) this.vx *= -1;
        if (this.y < 0 || this.y > canvas!.height) this.vy *= -1;

        // Mouse repulsion
        const dx = mouseX - this.x;
        const dy = mouseY - this.y;
        const distance = Math.sqrt(dx * dx + dy * dy);

        if (distance < mouseRepelDistance) {
          const forceDirectionX = dx / distance;
          const forceDirectionY = dy / distance;
          const force = (mouseRepelDistance - distance) / mouseRepelDistance;
          const repelStrength = 2; // Strength of repulsion

          this.vx -= forceDirectionX * force * repelStrength * 0.05;
          this.vy -= forceDirectionY * force * repelStrength * 0.05;
        }
      }

      draw() {
        if (!ctx) return;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = getNodeColor();
        ctx.fill();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      particles = [];
      for (let i = 0; i < particleCount; i++) {
        particles.push(new Particle());
      }
    };

    const animate = () => {
      if (!ctx) return;
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach((particle, index) => {
        particle.update();
        particle.draw();

        // Draw connections
        for (let j = index; j < particles.length; j++) {
          const dx = particles[j].x - particle.x;
          const dy = particles[j].y - particle.y;
          const distance = Math.sqrt(dx * dx + dy * dy);

          if (distance < connectionDistance) {
            ctx.beginPath();
            const opacity = 1 - distance / connectionDistance;
            ctx.strokeStyle = getLineColor(opacity * 0.5); // reduced opacity
            ctx.lineWidth = 1;
            ctx.moveTo(particle.x, particle.y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.stroke();
          }
        }
      });

      animationFrameId = requestAnimationFrame(animate);
    };

    const handleResize = () => {
      init();
    };

    const handleMouseMove = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      mouseX = e.clientX - rect.left;
      mouseY = e.clientY - rect.top;
    };

    const handleMouseLeave = () => {
      mouseX = -1000;
      mouseY = -1000;
    };

    window.addEventListener('resize', handleResize);
    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseout', handleMouseLeave);

    init();
    animate();

    return () => {
      window.removeEventListener('resize', handleResize);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseout', handleMouseLeave);
      cancelAnimationFrame(animationFrameId);
    };
  }, [theme]);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 w-full h-full pointer-events-none z-0 opacity-40 dark:opacity-30"
    />
  );
};

export default NeuralNetworkBackground;

import React, { useState, useMemo } from 'react';
import { Link, useLocation, useNavigate } from '../hooks/useAppContext';
import { useAuth } from '../hooks/useAuth';
import ThemeToggle from './ThemeToggle';
import Logo from './Logo';

const Header: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate();

  const isDashboard = location.pathname === '/dashboard';
  const isLanding = location.pathname === '/';
  const isCharting = location.pathname === '/charting';

  // Show back button if user is NOT on the primary dashboard/landing
  const showBack = !isLanding && !isDashboard;

  const pageTitle = useMemo(() => {
    const path = location.pathname;
    if (path === '/analysis') return 'Analysis Result';
    if (path === '/market-news') return 'Market News';
    if (path === '/predictor') return 'AI Event Predictor';
    if (path === '/journal') return 'Trading Journal';
    if (path === '/history') return 'Analysis History';
    if (path === '/apex-ai') return 'Apex AI Assistant';
    if (path === '/coders') return 'AI Coders Hub';
    return '';
  }, [location.pathname]);

  const navLinkClassName = "px-3 py-2 rounded-md text-sm font-medium transition-colors text-gray-300 hover:text-emerald-400 hover:bg-white/5 cursor-pointer";

  const handleBack = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (location.key === 'default') {
      navigate('/dashboard');
    } else {
      navigate(-1);
    }
  };

  const guestLinks = (isMobile = false) => {
    const mobileClass = isMobile ? 'block' : '';
    return (
        <>
            <Link 
              to="/#features" 
              onClick={(e) => {
                setIsOpen(false);
                if (isLanding) {
                    document.getElementById('features')?.scrollIntoView({ behavior: 'smooth' });
                }
              }} 
              className={`${navLinkClassName} ${mobileClass}`}
            >
              Features
            </Link>
            <Link to="/login" onClick={() => setIsOpen(false)} className={`${navLinkClassName} ${mobileClass}`}>Login</Link>
            <Link to="/signup" onClick={() => setIsOpen(false)} className={`${navLinkClassName} ${mobileClass}`}>Sign Up</Link>
        </>
    );
  };

  return (
    <header className={`bg-navy-900/80 backdrop-blur-lg sticky top-0 z-50 transition-all duration-300 transform-gpu glass-fix border-b border-white/10 ${isCharting ? 'h-10' : 'h-16'}`}>
      <div className="w-full h-full px-4">
        <div className="flex items-center justify-between h-full relative">

          {/* Left: Back Button or Logo */}
          <div className="flex-shrink-0 flex items-center z-[60] min-w-[100px]">
            {showBack ? (
                <button 
                  onClick={handleBack}
                  type="button"
                  className="flex items-center gap-2 text-gray-300 hover:text-emerald-400 transition-colors px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 ring-1 ring-transparent hover:ring-emerald-500/20 active:scale-95 cursor-pointer"
                >
                    <i className="fas fa-chevron-left text-xs"></i>
                    <span className="font-bold text-xs uppercase tracking-wider">Back</span>
                </button>
            ) : (
                <Logo />
            )}
          </div>

          {/* Center: Title (Only on subpages) */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
             {pageTitle && !isLanding && (
               <h1 className="text-white font-bold text-sm sm:text-base tracking-widest uppercase font-mono">
                 {pageTitle}
               </h1>
             )}
          </div>

          {/* Right: Controls */}
          <div className="flex items-center space-x-2 z-[60]">
            <ThemeToggle />
            {!user.isGuest ? (
               <button onClick={logout} className={`${navLinkClassName} whitespace-nowrap`}>Logout</button>
            ) : !isCharting && !isLanding && (
               <div className="hidden md:flex space-x-4">
                 {guestLinks()}
               </div>
            )}

            {/* Mobile Menu Toggle for Guest */}
            {user.isGuest && !isCharting && (
               <button
                  onClick={() => setIsOpen(!isOpen)}
                  type="button"
                  className="md:hidden ml-2 bg-white/5 inline-flex items-center justify-center p-2 rounded-md text-gray-400 hover:text-emerald-400 hover:bg-white/10 focus:outline-none"
              >
                  <svg className={`${isOpen ? 'hidden' : 'block'} h-5 w-5`} xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
                  </svg>
                  <svg className={`${isOpen ? 'block' : 'hidden'} h-5 w-5`} xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                  </svg>
              </button>
            )}
          </div>
        </div>
      </div>
      {isOpen && user.isGuest && !isCharting && (
        <div className="md:hidden bg-navy-900/95 backdrop-blur-xl border-b border-white/10">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
              {guestLinks(true)}
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;

